var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부대원들을 도와 줘서 고맙다, 나유빈. 네가 아니었으면 큰 피해를 입었겠어.","JPN":"部隊員への協力に感謝する、イチノセ・カオル。\\n君がいなければ被害はもっと大きかっただろう。","ENG":"Thank you for helping my troops, Yubin. We would've suffered massive casualties if it weren't for you.","TWN":"謝謝你救了我的部隊，羅瑜斌。如果不是你，我們恐怕會遭受極大的損失。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 최전선에서 싸우고 있던 것 아니었나? 어떻게 여기에 나타난 거지?","JPN":"しかし、最前線で戦っていたはずではなかったのか？\\nどうやってここにやって来たのだ？","ENG":"But weren't you fighting on the front lines? What are you doing here?","TWN":"但你不是應該在最前線戰鬥嗎？為什麼會在這裡？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최전선은 이미 무너졌습니다. 전멸 직전에 간신히 퇴각했죠.","JPN":"最前線はすでに崩壊しています。\\n全滅寸前に命からがら撤退してきました。","ENG":"We've already lost the front lines. We barely made it out before everyone got wiped out.","TWN":"最前線已經崩潰了，我們在全滅之前，好不容易才撤退掉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최대한 구하려고 했지만 생존자는 여기 있는 사람들이 전부입니다.","JPN":"可能な限り助けたかったのですが……\\n生存者はここにいる者で全員です。","ENG":"We tried our best to save as many folks as possible, but what you see here is all the survivors.","TWN":"雖然我盡可能地去救助其他人，但在這裡的就是全部的倖存者了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그나마 제 6종 침식체들이 갑자기 어딘가로 사라지지 않았더라면 아무도 살아남지 못했을 겁니다.","JPN":"もし第6種侵食体たちが急にどこかに\\n消えてくれていなければ、誰一人として生き残れなかったでしょう。","ENG":"We wouldn't have made it either if the Category 6 C.O.s didn't suddenly run off somewhere.","TWN":"如果不是6類侵蝕體突然消失，我們應該不會有人能活下來吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"힐데 전대장은? 그 사람이 있었는데도 패배했다는 건가?","JPN":"ヒルデ戦隊長は？　あの人がいたのに敗北したというのか？","ENG":"What about Commander Hilde? You were defeated even with her around?","TWN":"希爾德隊長呢？有她在我們怎麼可能會戰敗？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"스승님은...... 현재 실종 상태입니다.","JPN":"師匠は……現在、行方不明になっています。","ENG":"Master... is currently MIA.","TWN":"師父……目前是失蹤狀態。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 실종이라니?","JPN":"なんだと？　どういうことだ？","ENG":"What? She's missing in action?","TWN":"什麼？你說失蹤？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"으으......","JPN":"うぅ……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"여긴...... 여긴 어디야......?","JPN":"ここは……ここ、どこ……？","ENG":"Where... Where am I?","TWN":"這是……這裡是哪裡……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아! 정신이 들어?!","JPN":"キズナ！　気がついたのか！？","ENG":"Sooyeon! Have you come to?!","TWN":"秀妍！妳醒過來啦？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연?!","JPN":"カナミ！？","ENG":"Lee Sooyeon?","TWN":"李秀妍？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"류드...... 밀라......?","JPN":"リュド……ミラ……？","ENG":"Lyud... mila?","TWN":"盧德……米拉……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너, 이게 대체 어떻게 된 거냐!","JPN":"カナミ、いったいなんてザマだ！","ENG":"What happened to you?","TWN":"妳、妳到底是怎麼回事？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국 최강이라고 거들먹거리던 녀석이, 왜 이런 꼴로......!","JPN":"管理局最強だと威張っていた奴が、どうしてこんな姿に……！","ENG":"You were always bragging about being the best in the Administration... What happened?!","TWN":"妳不是老說自己是管理局最強制裁者嗎，怎麼會變成……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아윽......!","JPN":"あぅっ……！","ENG":"Ngh!","TWN":"嗚啊……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"전대장님, 수연이는 지금 중상을 입은 상태입니다.","JPN":"戦隊長、彼女は重症を負っています。","ENG":"Commander, Sooyeon has been heavily wounded.","TWN":"隊長，秀妍現在受了重傷。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"죄송하지만 질문은 나중에 해 주세요. 지금은 안정이 필요합니다.","JPN":"申し訳ないですが質問は後でお願いします。\\n今は安静にさせないと。","ENG":"I'd hate to be rude, but please save your questions for later. She needs to rest right now.","TWN":"雖然很抱歉，問題請妳之後再說吧，她現在需要休息。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만...... 관리국의 정예들이 이렇게까지 일방적으로 당하다니......","JPN":"しかし……管理局の精鋭たちがここまで一方的にやられるとは……","ENG":"But... I can't believe the Administration's finest operatives were defeated so helplessly...","TWN":"但是……管理局精銳竟然會單方面地……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"전대장! 정찰대로부터 긴급 보고야!","JPN":"戦隊長！　偵察隊から緊急報告！","ENG":"Commander! We got an urgent message from the recon team!","TWN":"隊長！偵察隊傳來了緊急報告！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"처음 보는 침식체가 이쪽으로 오고 있어! 생김새로 봐선 생존자들이 말한 6종 같아!","JPN":"初めて見る侵食体がこっちに来ているわよ！\\n見たところ、生存者たちの言っていた第6種だと思うわ！","ENG":"There's a C.O. coming this way, and we've never seen anything like it! It seems to match the survivors' description of the Category 6!","TWN":"有一隻沒見過的侵蝕體正朝這裡過來！看它的樣子，好像就是倖存者們說的6類！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런, 여기까지 추격해 왔나......!","JPN":"くっ、ここまで追撃してきたか……！","ENG":"Could it have followed them here?","TWN":"可惡，竟然追到這裡了……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"패잔병들은 애초에 전력으로 칠 수 없고, 우리 애들만으로는 막기 어려워.","JPN":"敗残兵は戦力として見込めないし、\\nうちの子どもたちだけでは防ぎきれないわ。","ENG":"The routed troops are currently incapable of fighting, and our kids are not enough to stall the enemy.","TWN":"殘兵不能成為戰力，單憑我們這些孩子們是擋不住的。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"놈과 마주치기 전에 어서 퇴각해야 돼. 다른 방법이 없어.","JPN":"奴と出くわす前に急いで退却すべきよ。もう打つ手がないもの。","ENG":"We have to retreat before it comes into contact. There's no other way.","TWN":"在被迫與它對決之前，必須立刻撤退才行，沒有別的方法了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"아뇨. 여기서 물러서선 안 됩니다.","JPN":"いいえ。ここで引き下がってはなりません。","ENG":"No. We cannot back down right now.","TWN":"不，不能在這裡撤退。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"전투에 대비해 주세요. 전방은 제가 맡겠습니다.","JPN":"戦闘に備えてください。前は僕が引き受けます。","ENG":"Please prepare for battle. I'll take point.","TWN":"請準備戰鬥，前方就交給我了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"들은 것과 다르게 호전적이군. 이수연은 네가 너무 신중하다고 투덜거리기 일쑤였는데.","JPN":"前に聞いていた話と違って好戦的だな。\\nカナミはお前が慎重すぎるとよくボヤいていたが。","ENG":"You're a lot more belligerent than I've heard. Sooyeon always complained that you were too careful.","TWN":"和我聽到的不一樣，還真是積極啊。李秀妍總是說你謹慎又老愛抱怨。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아니면, 피하지 않고 싸워야 할 이유가 있는 건가?","JPN":"それとも、戦いを避けられない理由でもあるのか？","ENG":"Or is there a specific reason why we must fight it instead of fleeing?","TWN":"還是說，你有不能退縮，必須要戰鬥的理由？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"방어선이 무너지기 전, 하이브 컨트롤이 관리국 최종 프로토콜 <color=#ffd34c>CoW</color>를 발동했습니다.","JPN":"防衛線が崩壊する直前、ハイブコントロールが\\n管理局最終プロトコル<color=#ffd34c>CoW</color>を発動しました。","ENG":"Before our line of defense fell, Hive Control activated the Administration's final protocol, <color=#ffd34c>CoW</color>.","TWN":"在防線崩潰之前，巢穴控制系統發動了管理局最終協議<color=#ffd34c>CoW</color>。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"최종 프로토콜?","JPN":"最終プロトコル？","ENG":"The final protocol?","TWN":"最終協議？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......관리국이 파멸 상황에 직면했을 때 발동되는 최종 작전 계획입니다.","JPN":"……管理局が破滅寸前に追い込まれた際に\\n発動される最終作戦計画です。","ENG":"It's the final operation plan that's activated when the Administration's on the brink of destruction.","TWN":"……是管理局面臨滅亡狀況時，發動的最終作戰計畫。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자만 접근 가능한 내용이라 들어보신 적이 없는 게 당연할 겁니다.","JPN":"最高管理者のみがアクセス可能な内容ですので、\\nご存知ないのは当然かと思います。","ENG":"Only the Supreme Administrator has the clearance to access this, so it's no surprise you haven't heard of it.","TWN":"這是只有最高管理者才能接觸到的機密，妳會不知道是當然的。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"확실히 처음 듣는 지침이군.","JPN":"確かに聞いたことのない話だが。","ENG":"I've certainly never heard of this directive.","TWN":"我確實是第一次聽說。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 부전대장인 네가 어떻게 그런 기밀 사항을 알고 있는 거냐?","JPN":"ただの副戦隊長である君がなぜそんな機密事項を知り得たのだ？","ENG":"Then how does a mere deputy division commander like you know about this?","TWN":"不過你一個副隊長怎麼會知道這樣的機密事項？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這是……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"말싸움은 나중에 해! 놈이 곧 교전거리로 들어온다고!","JPN":"話は後にして！　もうすぐ交戦距離に踏み込まれるわ！","ENG":"Save the chitchat for later! It's going to be in range soon!","TWN":"要吵架之後再吵！它們馬上就要進入交戰距離了！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"죄송합니다. 어떻게 알았는지 말씀드릴 수는 없습니다.","JPN":"申し訳ありません。なぜ知ることができたかを\\nお教えすることはできないんです。","ENG":"I'm sorry. I can't tell you how I learned of this.","TWN":"很抱歉，我沒辦法告訴妳... 我是怎麼知道的。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금은 시간이 없어요. 최대한 서둘러서 <color=#ffd34c>방주</color>로 가야 합니다.","JPN":"とにかく、今は時間がありません。\\nなるべく急いで<color=#ffd34c>箱舟</color>へ向かわなければ。","ENG":"But we're running out of time now. We must hurry to <color=#ffd34c>the Ark</color>.","TWN":"但現在沒有時間了，必須要以最快的速度前往<color=#ffd34c>方舟</color>。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"프로토콜의 마지막 단계인 시공간 종료가 시작되기 전에요!","JPN":"プロトコルの最終段階、時空間終了が始まる前に！","ENG":"We have to get there before the last phase of the protocol, before the spacetime abortion sequence begins!","TWN":"協議的最終階段，時空終止馬上就要開始了！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스, 전투 준비해. 접근 중인 적을 요격한다.","JPN":"アレックス、戦闘用意を。接近中の敵を迎撃する。","ENG":"Get ready for battle, Alex. I'm going to intercept the incoming hostile.","TWN":"雅蕾克絲，準備戰鬥，迎擊接近的敵人。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기다려! 제정신이야? 머리에 총 맞았어?!","JPN":"ちょっと！　何を言ってるの？　頭でもぶつけちゃったの！？","ENG":"Wait! Are you insane? Did you take a bullet to the head?!","TWN":"等等！妳瘋了嗎？妳腦袋是壞掉了？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들을 살리기 위해선 이 방법이 최선이라고 판단했을 뿐이다. 이상.","JPN":"これが隊員たちを救う最善の方法と判断したまでだ。以上。","ENG":"It's my assessment that this is the best course of action to maximize the troops' chance of survival. Over and out.","TWN":"為了讓隊員活下去，我判斷這是最好的方法，完畢。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"끊지 마! 설명은 해 줘야 할 거 아냐!","JPN":"切らないで！　ちゃんと説明してちょうだい！","ENG":"Don't you hang up on me! You owe me an explanation!","TWN":"別掛斷！至少跟我解釋一下啊！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라!","JPN":"リュドミラちゃん！","ENG":"Lyudmila!","TWN":"盧德米拉！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......전대장님.","JPN":"……戦隊長。","ENG":"Commander.","TWN":"……隊長。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 아는 너라면 수연이를 위험에 빠트릴 만한 선택은 하지 않겠지.","JPN":"私の知っている君ならキズナを危険に晒すような選択はしないはずだ。","ENG":"I know you won't do anything to put Sooyeon in danger.","TWN":"我所認識的你，不會做出讓秀妍陷入危險的選擇。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 대신, 실력 발휘는 확실히 해 줘야겠어.","JPN":"こうなったら、君にも一肌脱いでもらうぞ。","ENG":"But you'd better give this your best.","TWN":"但相對的，你得發揮你的實力才行。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};